{
  "mode": "io",
  "tests": [
    {
      "name": "basic_resizing_1080x1920",
      "input": {
        "image": "base_image_1080x1920.jpg",
        "target_resolution": [1080, 1920]
      },
      "output": "output_image_1080x1920.jpg",
      "notes": "Tests basic resizing functionality to the target resolution without losing key content."
    },
    {
      "name": "basic_resizing_1200x628",
      "input": {
        "image": "base_image_1200x800.jpg",
        "target_resolution": [1200, 628]
      },
      "output": "output_image_1200x628.jpg",
      "notes": "Validates resizing and cropping to a different aspect ratio while maintaining focal points."
    },
    {
      "name": "focal_point_face_centric",
      "input": {
        "image": "base_image_face_centric.jpg",
        "target_resolution": [800, 800],
        "focal_point": "face"
      },
      "output": "output_image_face_centric_800x800.jpg",
      "notes": "Ensures that the face is preserved in the center of the cropped image."
    },
    {
      "name": "focal_point_product_centric",
      "input": {
        "image": "base_image_product_centric.jpg",
        "target_resolution": [1200, 1200],
        "focal_point": "product"
      },
      "output": "output_image_product_centric_1200x1200.jpg",
      "notes": "Validates that the product remains in focus during resizing."
    },
    {
      "name": "edge_case_small_image",
      "input": {
        "image": "small_image_100x100.jpg",
        "target_resolution": [1080, 1920]
      },
      "output": "output_image_small_1080x1920.jpg",
      "notes": "Tests how the algorithm handles a very small input image and upscales it."
    },
    {
      "name": "edge_case_large_image",
      "input": {
        "image": "large_image_4000x3000.jpg",
        "target_resolution": [1920, 1080]
      },
      "output": "output_image_large_1920x1080.jpg",
      "notes": "Validates the algorithm's ability to downscale a large image while preserving quality."
    },
    {
      "name": "background_extension",
      "input": {
        "image": "base_image_with_background.jpg",
        "target_resolution": [1600, 900],
        "extend_background": true
      },
      "output": "output_image_extended_background_1600x900.jpg",
      "notes": "Tests the background extension feature to fill the new dimensions without losing key content."
    },
    {
      "name": "multiple_aspect_ratios",
      "input": {
        "image": "base_image_multiple_aspect.jpg",
        "target_resolutions": [[1080, 1920], [1200, 628], [800, 800]]
      },
      "output": [
        "output_image_1080x1920.jpg",
        "output_image_1200x628.jpg",
        "output_image_800x800.jpg"
      ],
      "notes": "Validates the ability to generate multiple outputs from a single input image."
    }
  ],
  "assumptions": "The input images are valid and accessible. The target resolutions are specified correctly.",
  "notes": "Ensure that the outputs maintain visual fidelity and do not distort key subjects."
}
